t;span class=&quot;NormalTextRun SCXW189697405 BCX0&quot;&gt;assistance&lt;/span&gt;&lt;span class=&quot;NormalTextRun SCXW189697405 BCX0&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span class=&quot;NormalTextRun SCXW189697405 BCX0&quot;&gt;in developing&lt;/span&gt;&lt;span class=&quot;NormalTextRun SCXW189697405 BCX0&quot;&gt;&amp;nbsp;cardiovascular disease prevention programs&lt;/span&gt;&lt;span class=&quot;NormalTextRun SCXW189697405 BCX0&quot;&gt;&amp;nbsp;to help countries improve the heart health of their people.&lt;/span&gt;&lt;span class=&quot;NormalTextRun SCXW189697405 BCX0&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;TextRun SCXW189697405 BCX0&quot; lang=&quot;EN-US&quot; data-contrast=&quot;none&quot;&gt;&lt;span class=&quot;NormalTextRun SCXW189697405 BCX0&quot;&gt;Working with our partners to improve the control of high blood pressure, reduce salt intake, and&amp;nbsp;&lt;/span&gt;&lt;span class=&quot;NormalTextRun SCXW189697405 BCX0&quot;&gt;eliminate&lt;/span&gt;&lt;span class=&quot;NormalTextRun SCXW189697405 BCX0&quot;&gt; trans fats from the global food supply, the CVH team has helped save countless lives from cardiovascular disease.&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
